// Option 1: OneOf<> thư viện (NuGet: OneOf)
using OneOf;
public OneOf<OrderDto, NotFound, Forbidden> GetOrder(int id, int userId) =>
    _orders.TryGetValue(id, out var o) switch
    {
        false => new NotFound(),
        true when o.OwnerId != userId => new Forbidden(),
        true => _mapper.ToDto(o)
    };

