// Option 2: Sealed class hierarchy + pattern matching
public abstract record GetOrderResult;
public record OrderFound(OrderDto Order) : GetOrderResult;
public sealed record OrderNotFound : GetOrderResult;
public sealed record OrderForbidden : GetOrderResult;

string HandleResult(GetOrderResult result) => result switch
{
    OrderFound(var o) => $"Order {o.Id}",
    OrderNotFound => "Not found",
    OrderForbidden => "Forbidden",
    _ => throw new UnreachableException() // compiler không exhaustive check với record
};

